 40→public class ParameterListWrappingRule :
 41→    StandardRule(
 42→        id = "parameter-list-wrapping",
 43→        usesEditorConfigProperties =
 44→            setOf(
 45→                CODE_STYLE_PROPERTY,
 46→                INDENT_SIZE_PROPERTY,
 47→                INDENT_STYLE_PROPERTY,
 48→                MAX_LINE_LENGTH_PROPERTY,
 49→            ),
 50→    ) {
 51→    private var codeStyle = CODE_STYLE_PROPERTY.defaultValue
 52→    private var indentConfig = IndentConfig.DEFAULT_INDENT_CONFIG
 53→    private var maxLineLength = MAX_LINE_LENGTH_PROPERTY.defaultValue
 54→
 55→    override fun beforeFirstNode(editorConfig: EditorConfig) {
 56→        codeStyle = editorConfig[CODE_STYLE_PROPERTY]
 57→        maxLineLength = editorConfig[MAX_LINE_LENGTH_PROPERTY]
 58→        indentConfig =
 59→            IndentConfig(
 60→                indentStyle = editorConfig[INDENT_STYLE_PROPERTY],
 61→                tabWidth = editorConfig[INDENT_SIZE_PROPERTY],
 62→            )
 63→        if (indentConfig.disabled) {
 64→            stopTraversalOfAST()
 65→        }
 66→    }
 67→
 68→    override fun beforeVisitChildNodes(
 69→        node: ASTNode,
 70→        autoCorrect: Boolean,
 71→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 72→    ) {
 73→        when (node.elementType) {
 74→            NULLABLE_TYPE -> wrapNullableType(node, emit, autoCorrect)
 75→            VALUE_PARAMETER_LIST -> {
 76→                if (node.needToWrapParameterList()) {
 77→                    wrapParameterList(node, emit, autoCorrect)
 78→                }
 79→            }
 80→        }
 81→    }
 82→
 83→    private fun wrapNullableType(
 84→        node: ASTNode,
 85→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 86→        autoCorrect: Boolean,
 87→    ) {
 88→        require(node.elementType == NULLABLE_TYPE)
 89→        node
 90→            .takeUnless {
 91→                // skip when max line length is not exceedd
 92→                (node.column - 1 + node.textLength) <= maxLineLength
 93→            }?.findChildByType(FUNCTION_TYPE)
 94→            ?.findChildByType(VALUE_PARAMETER_LIST)
 95→            ?.takeIf { it.findChildByType(VALUE_PARAMETER) != null }
 96→            ?.takeUnless { it.textContains('\n') }
 97→            ?.let {
 98→                node
 99→                    .children()
100→                    .forEach {
101→                        when (it.elementType) {
102→                            LPAR -> {
103→                                emit(
104→                                    it.startOffset,
105→                                    "Parameter of nullable type should be on a separate line (unless the type fits on a single line)",
106→                                    true,
107→                                )
108→                                if (autoCorrect) {
109→                                    it.upsertWhitespaceAfterMe(indentConfig.childIndentOf(node))
110→                                }
111→                            }
112→                            RPAR -> {
113→                                emit(it.startOffset, errorMessage(it), true)
114→                                if (autoCorrect) {
115→                                    it.upsertWhitespaceBeforeMe(indentConfig.parentIndentOf(node))
116→                                }
117→                            }
118→                        }
119→                    }
120→            }
121→    }
122→
123→    private fun ASTNode.needToWrapParameterList() =
124→        when {
125→            hasNoParameters() -> false
126→            codeStyle != ktlint_official && isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle() -> false
127→            codeStyle == ktlint_official && isPartOfFunctionLiteralStartingOnSameLineAsClosingParenthesisOfPrecedingReferenceExpression() ->
128→                false
129→            isFunctionTypeWrappedInNullableType() -> false
130→            textContains('\n') -> true
131→            codeStyle == ktlint_official && containsAnnotatedParameter() -> true
132→            exceedsMaxLineLength() -> true
133→            else -> false
134→        }
135→
136→    private fun ASTNode.hasNoParameters(): Boolean {
137→        require(elementType == VALUE_PARAMETER_LIST)
138→        return firstChildNode?.treeNext?.elementType == RPAR
139→    }
140→
141→    private fun ASTNode.isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle(): Boolean {
142→        require(elementType == VALUE_PARAMETER_LIST)
143→        return treeParent?.elementType == FUNCTION_LITERAL
144→    }
145→
146→    private fun ASTNode.isPartOfFunctionLiteralStartingOnSameLineAsClosingParenthesisOfPrecedingReferenceExpression(): Boolean {
147→        require(elementType == VALUE_PARAMETER_LIST)
148→        return firstChildLeafOrSelf()
149→            .let { startOfFunctionLiteral ->
150→                treeParent
151→                    ?.takeIf { it.elementType == FUNCTION_LITERAL }
152→                    ?.prevCodeLeaf()
153→                    ?.takeIf { it.treeParent.elementType == ElementType.VALUE_ARGUMENT_LIST }
154→                    ?.takeIf { it.treeParent.treeParent.elementType == ElementType.CALL_EXPRESSION }
155→                    ?.leaves()
156→                    ?.takeWhile { it != startOfFunctionLiteral }
157→                    ?.none { it.isWhiteSpaceWithNewline() }
158→                    ?: false
159→            }
160→    }
161→
162→    private fun ASTNode.isFunctionTypeWrappedInNullableType(): Boolean {
163→        require(elementType == VALUE_PARAMETER_LIST)
164→        return treeParent.elementType == FUNCTION_TYPE && treeParent?.treeParent?.elementType == NULLABLE_TYPE
165→    }
166→
167→    private fun ASTNode.containsAnnotatedParameter(): Boolean {
168→        require(elementType == VALUE_PARAMETER_LIST)
169→        return this.children()
170→            .filter { it.elementType == VALUE_PARAMETER }
171→            .any { it.isAnnotated() }
172→    }
173→
174→    private fun ASTNode.isAnnotated() =
175→        findChildByType(ElementType.MODIFIER_LIST)
176→            ?.children()
177→            .orEmpty()
178→            .any { it.elementType == ElementType.ANNOTATION_ENTRY }
179→
180→    private fun wrapParameterList(
181→        node: ASTNode,
182→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
183→        autoCorrect: Boolean,
184→    ) {
185→        node
186→            .children()
187→            .forEach { child -> wrapParameterInList(child, emit, autoCorrect) }
188→    }
189→
190→    private fun intendedIndent(child: ASTNode): String =
191→        when {
192→            // IDEA quirk:
193→            // fun <
194→            //     T,
195→            //     R> test(
196→            //     param1: T
197→            //     param2: R
198→            // )
199→            // instead of
200→            // fun <
201→            //     T,
202→            //     R> test(
203→            //         param1: T
204→            //         param2: R
205→            //     )
206→            child.treeParent.hasTypeParameterListInFront() -> -1
207→
208→            else -> 0
209→        }.let {
210→            if (child.elementType == VALUE_PARAMETER) {
211→                it + 1
212→            } else {
213→                it
214→            }
215→        }.let { indentLevelFix ->
216→            val indentLevel =
217→                indentConfig
218→                    .indentLevelFrom(child.treeParent.indent(false))
219→                    .plus(indentLevelFix)
220→            "\n" + indentConfig.indent.repeat(indentLevel)
221→        }
222→
223→    private fun wrapParameterInList(
224→        child: ASTNode,
225→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
226→        autoCorrect: Boolean,
227→    ) {
228→        when (child.elementType) {
229→            LPAR -> {
230→                val prevLeaf = child.prevLeaf()
231→                if (prevLeaf is PsiWhiteSpace && prevLeaf.textContains('\n')) {
232→                    emit(child.startOffset, errorMessage(child), true)
233→                    if (autoCorrect) {
234→                        prevLeaf.delete()
235→                    }
236→                }
237→            }
238→            VALUE_PARAMETER,
239→            RPAR,
240→            -> {
241→                // aiming for
242→                // ... LPAR
243→                // <line indent + indentSize> VALUE_PARAMETER...
244→                // <line indent> RPAR
245→                val intendedIndent = intendedIndent(child)
246→                val prevLeaf = child.prevLeaf()
247→                if (prevLeaf is PsiWhiteSpace) {
248→                    if (prevLeaf.getText().contains("\n")) {
249→                        // The current child is already wrapped to a new line. Checking and fixing the
250→                        // correct size of the indent is the responsibility of the IndentationRule.
251→                        return
252→                    } else {
253→                        // The current child needs to be wrapped to a newline.
254→                        emit(child.startOffset, errorMessage(child), true)
255→                        if (autoCorrect) {
256→                            // The indentation is purely based on the previous leaf only. Note that in
257→                            // autoCorrect mode the indent rule, if enabled, runs after this rule and
258→                            // determines the final indentation. But if the indent rule is disabled then the
259→                            // indent of this rule is kept.
260→                            (prevLeaf as LeafPsiElement).rawReplaceWithText(intendedIndent)
261→                        }
262→                    }
263→                } else {
264→                    // Insert a new whitespace element in order to wrap the current child to a new line.
265→                    emit(child.startOffset, errorMessage(child), true)
266→                    if (autoCorrect) {
267→                        child.treeParent.addChild(PsiWhiteSpaceImpl(intendedIndent), child)
268→                    }
269→                }
270→                // Indentation of child nodes need to be fixed by the IndentationRule.
271→            }
272→        }
273→    }
274→
275→    private fun ASTNode.exceedsMaxLineLength() = (column - 1 + textLength) > maxLineLength && !textContains('\n')
276→
277→    private fun errorMessage(node: ASTNode) =
278→        when (node.elementType) {
279→            LPAR -> """Unnecessary newline before "(""""
280→            VALUE_PARAMETER ->
281→                "Parameter should start on a newline"
282→            RPAR -> """Missing newline before ")""""
283→            else -> throw UnsupportedOperationException()
284→        }
285→
286→    private fun ASTNode.hasTypeParameterListInFront(): Boolean {
287→        val parent = this.treeParent
288→        val typeParameterList =
289→            if (parent.elementType == PRIMARY_CONSTRUCTOR) {
290→                parent.prevSibling { it.elementType == TYPE_PARAMETER_LIST }
291→            } else {
292→                parent.children().firstOrNull { it.elementType == TYPE_PARAMETER_LIST }
293→            }
294→        val typeListNode =
295→            typeParameterList
296→                ?: parent.psi.collectDescendantsOfType<KtTypeArgumentList>().firstOrNull()?.node
297→                ?: return false
298→        return typeListNode.children().any { it.isWhiteSpaceWithNewline() }
299→    }
300→}
301→
302→public val PARAMETER_LIST_WRAPPING_RULE_ID: RuleId = ParameterListWrappingRule().ruleId
303→

