    private fun intendedIndentForNullableType(child: ASTNode, nullableTypeNode: ASTNode): String {
        // For nullable function types, we want to indent the inner parameters
        // one level deeper than the outer parentheses
        val baseIndent = indentConfig.childIndentOf(nullableTypeNode)
